const DAFNA_MSGS=["אין דרך אחת נכונה ללדת. יש את הדרך שנכונה לך.","ידע נותן ביטחון, אבל גם הקשבה לעצמך.","לידה היא לא מבחן.","הנקה היא מיומנות שלומדים.","לפעמים לבקש עזרה זו הבחירה הכי אמיצה.","כל לידה היא סיפור אחר.","גם אם התוכנית משתנה, אפשר עדיין לחוות לידה טובה.","את לא צריכה לדעת הכול כבר עכשיו.","הגוף שלך יודע הרבה יותר ממה שנדמה לך.","אני מאמינה בגוף שלך.","ואני מאמינה גם בך.","אל תפחדי לשאול שאלות.","ההכנה הכי טובה ללידה היא ידע וביטחון.","גם אם יש רגעים של פחד – הם לא מגדירים אותך.","את לא לבד במסע הזה.","כל אישה חווה הריון אחרת.","לא תמיד צריך לשלוט בהכול.","גם מנוחה היא הכנה ללידה.","אני רוצה שתסמכי גם על האינטואיציה שלך.","את עושה עבודה מדהימה.","התינוק שלך לא מחפש אמא מושלמת – הוא מחפש אותך.","גם אם משהו לא הלך לפי התכנון – זה לא אומר שנכשלת.","הרבה דברים בלידה אי אפשר לשלוט בהם, אבל אפשר להתכונן אליהם.","נשימה אחת יכולה לשנות רגע שלם.","הריון הוא גם מסע פנימי.","כל שבוע שעובר מקרב אותך אליו.","אל תשכחי לדאוג גם לעצמך.","הלידה היא יום אחד. האימהות היא דרך חיים.","תני לעצמך קרדיט.","לפעמים הדבר החשוב ביותר הוא פשוט להרגיש בטוחה."];;

function MomentCard({type}) {
  const msgs=type==='dafna'?DAFNA_MSGS:MOMENT_MSGS;
  const [msg]=useState(()=>msgs[Math.floor(Math.random()*msgs.length)]);
  const isDafna=type==='dafna';
  const lblD='💛 רגע עם דפנה';const lblM='🌿 רגע בשבילך';const lbl=isDafna?lblD:lblM;
  return (
    <div style={{borderRadius:12,padding:'14px 16px',marginTop:12,marginBottom:4,background:isDafna?'#FFF8E1':'#F0FFF4',borderRight:`3px solid ${isDafna?'#F9A825':'#81C784'}`}}>
      <div style={{fontSize:11,fontWeight:600,color:isDafna?'#F9A825':'#388E3C',marginBottom:6}}>{lbl}</div>
      <div style={{fontSize:13,color:'#3A2E28',lineHeight:1.7,fontStyle:'italic'}}>{msg}</div>
    </div>
  );
}
